// Add to BatchProcessor class
class BatchProcessor : public std::enable_shared_from_this<BatchProcessor>,
                       public IPoolAwareService
{
    tbb::task_arena* _arena = nullptr;

public:
    void setTaskArena(tbb::task_arena* arena) override {
        _arena = arena;
    }

    // Modify workerLoop() at line 218:
    void workerLoop()
    {
        tbb::task_group tg;

        auto executeInArena = [this, &tg](auto&& task) {
            if (_arena) {
                _arena->execute([&] { tg.run(std::forward<decltype(task)>(task)); });
            } else {
                tg.run(std::forward<decltype(task)>(task));
            }
        };

        while (!stopped_.load() || !requestQueue_.empty())
        {
            BatchRequest req;
            if (requestQueue_.try_pop(req))
            {
                auto self = shared_from_this();
                executeInArena([this, self, r = std::move(req)]() mutable {
                    processBatch(std::move(r));
                });
                // ... rest of throttling logic ...
            }
            // ...
        }
        tg.wait();
    }
};
```

