class ETLPipeline : public std::enable_shared_from_this<ETLPipeline>,
                    public IPoolAwareService
{
    tbb::task_arena* _arena = nullptr;

public:
    void setTaskArena(tbb::task_arena* arena) override {
        _arena = arena;
    }

    // Modify runLoop() at line 398:
    void runLoop()
    {
        auto executeGraph = [this] {
            tbb::flow::graph g;

            using Batch = std::vector<PatientDataRecord>;

            tbb::flow::function_node<Batch> transformNode(
                g,
                cfg_.transformer_concurrency,
                [this](Batch batch) {
                    // ... existing transformation logic ...
                });

            while (running_)
            {
                Batch batch;
                if (!extractor_->extract(batch))
                {
                    running_ = false;
                    break;
                }
                transformNode.try_put(std::move(batch));
            }

            g.wait_for_all();
        };

        if (_arena) {
            _arena->execute(executeGraph);
        } else {
            executeGraph();
        }
    }
};
```

