    47→class KafkaRebalanceCb final : public RdKafka::RebalanceCb {
    48→public:
    49→    void rebalance_cb(RdKafka::KafkaConsumer* consumer,
    50→                      RdKafka::ErrorCode err,
    51→                      std::vector<RdKafka::TopicPartition*>& partitions) override {
    52→        switch (err) {
    53→        case RdKafka::ERR__ASSIGN_PARTITIONS:
