    58→            Logger::debug("IngestionService: Partition revocation received.");
    59→            consumer->unassign();
    60→            break;
    61→        default:
    62→            Logger::warn("IngestionService: Rebalance error: {}", RdKafka::err2str(err));
    63→            consumer->unassign();
    64→            break;
    65→        }
    66→    }
