   113→    globalConf->set("fetch.wait.max.ms", std::to_string(config_.fetchWaitMs), err);
   114→    globalConf->set("event_cb", &eventCb_, err);
   115→    globalConf->set("rebalance_cb", &rebalanceCb_, err);
   116→
   117→    consumer_.reset(RdKafka::KafkaConsumer::create(globalConf.get(), err));
   118→    if (!consumer_) {
   119→        throw std::runtime_error("Failed to create KafkaConsumer: " + err);
   120→    }
   121→
   122→    Logger::info("Kafka consumer created: {}", consumer_->name());
   123→
   124→    /* Subscribe to topic */
   125→    auto errCode = consumer_->subscribe({config_.kafkaTopic});
   126→    if (errCode != RdKafka::ERR_NO_ERROR) {
   127→        throw std::runtime_error("Failed to subscribe to topic: " + RdKafka::err2str(errCode));
   128→    }
   129→
   130→    /* Pre-allocate helper objects */
   131→    parser_     = std::make_unique<HL7Parser>();
   132→    validator_  = std::make_unique<HL7Validator>();
   133→    dataLake_   = std::make_unique<DataLakeFacade>(config_.dataLakeRoot);
