   143→void IngestionService::start() {
   144→    if (running_) return;
   145→    running_ = true;
   146→
   147→    MetricsCollector::instance().set("ingestion.running_state", 1);
   148→
   149→    /* Spawn worker thread (detached) */
   150→    worker_ = std::thread([this] { consumeLoop(); });
   151→    Logger::info("IngestionService: Started.");
   152→}
