   154→void IngestionService::stop() {
   155→    if (!running_) return;
   156→    running_ = false;
   157→
   158→    Logger::info("IngestionService: Stopping…");
   159→
   160→    /* Shut down Kafka consumer gracefully */
   161→    if (consumer_) {
   162→        consumer_->close();
   163→    }
   164→
   165→    /* Join worker thread */
   166→    if (worker_.joinable()) {
   167→        worker_.join();
   168→    }
   169→
   170→    MetricsCollector::instance().set("ingestion.running_state", 0);
   171→    Logger::info("IngestionService: Stopped.");
   172→}
