   174→void IngestionService::consumeLoop() noexcept {
   175→    const int kPollTimeoutMs = 100;
   176→
   177→    while (running_) {
   178→        std::unique_ptr<RdKafka::Message> msg{consumer_->consume(kPollTimeoutMs)};
   179→        switch (msg->err()) {
   180→        case RdKafka::ERR_NO_ERROR:
   181→            /* Process message inside TBB arena for scalability */
   182→            arena_.execute([this, payload = std::string{static_cast<const char*>(msg->payload()), msg->len()}] {
   183→                processMessage(payload);
   184→            });
   185→            break;
   186→
   187→        case RdKafka::ERR__TIMED_OUT:
   188→            /* Poll timeout; nothing to do */
   189→            break;
   190→
   191→        default:
   192→            Logger::warn("Kafka ingestion error: {}", msg->errstr());
   193→            MetricsCollector::instance().increment("ingestion.kafka.consume_error_total");
   194→            break;
   195→        }
   196→    }
   197→}
