   199→void IngestionService::processMessage(const std::string& rawMsg) noexcept {
   200→    SpanGuard span("IngestionService::processMessage"); // OpenTracing helper
   201→
   202→    try {
   203→        MetricsCollector::instance().increment("ingestion.msg_received_total");
   204→
   205→        /* 1. Parse */
   206→        auto hl7Message = parser_->parse(rawMsg);
   207→
   208→        /* 2. Validate business rules */
   209→        if (!validator_->validate(*hl7Message)) {
   210→            MetricsCollector::instance().increment("ingestion.msg_invalid_total");
   211→            Logger::warn("IngestionService: Validation failed. Message dropped.");
   212→            return;
   213→        }
   214→
   215→        /* 3. Persist raw data (append-mode) */
   216→        dataLake_->appendRaw(hl7Message->timestamp, rawMsg);
   217→
   218→        /* 4. Publish to internal Event-Bus for downstream processing */
   219→        eventBus_->publish(Event{
   220→            .timestamp = hl7Message->timestamp,
   221→            .payload   = hl7Message->toJson(),
   222→            .type      = EventType::HL7_INGESTED
   223→        });
   224→
   225→        MetricsCollector::instance().increment("ingestion.msg_processed_total");
   226→    } catch (const std::exception& ex) {
   227→        MetricsCollector::instance().increment("ingestion.msg_exception_total");
   228→        Logger::error("IngestionService: Exception while processing message – {}", ex.what());
   229→    }
   230→}
