   212→void EventBusFacade::Impl::initProducer()
   213→{
   214→    _producerConf.reset(RdKafka::Conf::create(RdKafka::Conf::CONF_GLOBAL));
   215→    if (!_producerConf)
   216→    {
   217→        throw std::runtime_error("Failed to create global kafka conf");
   218→    }
   219→
   220→    std::string errStr;
   221→
   222→    const auto bootstrap = _cfg.getString("event_bus.bootstrap_servers", "localhost:9092");
   223→    if (_producerConf->set("bootstrap.servers", bootstrap, errStr) != RdKafka::Conf::CONF_OK)
   224→    {
   225→        throw std::runtime_error("Producer set(bootstrap.servers): " + errStr);
   226→    }
   227→
   228→    _producerConf->set("enable.idempotence", "false", errStr); // at-most-once
   229→
   230→    // Hook up delivery callback
   231→    if (_producerConf->set("dr_cb", &_deliveryCb, errStr) != RdKafka::Conf::CONF_OK)
   232→    {
   233→        throw std::runtime_error("Producer set(dr_cb): " + errStr);
   234→    }
