   245→EventBusFacade::Impl::ConsumerPtr EventBusFacade::Impl::createConsumer(const std::string &topic)
   246→{
   247→    std::unique_ptr<RdKafka::Conf> conf(RdKafka::Conf::create(RdKafka::Conf::CONF_GLOBAL));
   248→    if (!conf)
   249→    {
   250→        throw std::runtime_error("Failed to create consumer conf");
   251→    }
   252→
   253→    std::string errStr;
   254→    const auto bootstrap = _cfg.getString("event_bus.bootstrap_servers", "localhost:9092");
   255→    conf->set("bootstrap.servers", bootstrap, errStr);
   256→    conf->set("group.id", makeConsumerGroupId(topic), errStr);
   257→    conf->set("auto.offset.reset", "earliest", errStr);
   258→    conf->set("enable.auto.commit", "true", errStr);
   259→    conf->set("enable.partition.eof", "false", errStr);
   260→
   261→    static RebalanceCb rebalanceCb(_metrics);
   262→    conf->set("rebalance_cb", &rebalanceCb, errStr);
   263→
   264→    ConsumerPtr consumer(RdKafka::KafkaConsumer::create(conf.get(), errStr));
   265→    if (!consumer)
   266→    {
   267→        throw std::runtime_error("Failed to create consumer: " + errStr);
   268→    }
   269→
   270→    const RdKafka::ErrorCode ret = consumer->subscribe({ topic });
   271→    if (ret != RdKafka::ERR_NO_ERROR)
   272→    {
   273→        throw std::runtime_error("Failed to subscribe to topic " + topic + ": "
   274→                                 + RdKafka::err2str(ret));
