   292→void EventBusFacade::Impl::start()
   293→{
   294→    if (_running.exchange(true))
   295→    {
   296→        return; // already running
   297→    }
   298→
   299→    // Launch a thread per subscribed topic – simpler than polling all in one
   300→    std::scoped_lock lock(_callbacksMtx);
   301→    for (auto &[topic, cb] : _callbacks)
   302→    {
   303→        ConsumerPtr consumer = createConsumer(topic);
   304→
   305→        _consumerThreads.emplace_back(
   306→            [this, topic, cons = std::move(consumer)]() mutable
   307→            { consumerLoop(topic, std::move(cons)); });
   308→    }
   309→
   310→    LOG_INFO("[EventBus] Started with {} consumer threads", _consumerThreads.size());
   311→}
