   313→void EventBusFacade::Impl::shutdown()
   314→{
   315→    if (!_running.exchange(false))
   316→    {
   317→        return; // already stopped
   318→    }
   319→
   320→    // Drain producer
   321→    _producer->flush(5'000);
   322→
   323→    // Join consumer threads
   324→    for (auto &t : _consumerThreads)
   325→    {
   326→        if (t.joinable())
   327→        {
   328→            t.join();
   329→        }
   330→    }
   331→    _consumerThreads.clear();
   332→
   333→    LOG_INFO("[EventBus] Shutdown completed");
   334→}
