   336→bool EventBusFacade::Impl::publish(const std::string            &topic,
   337→                                   const std::string            &key,
   338→                                   const nlohmann::json         &payload,
   339→                                   std::chrono::milliseconds     timeout)
   340→{
   341→    const std::string serialized = payload.dump();
   342→
   343→    RdKafka::ErrorCode err = _producer->produce(
   344→        topic,
   345→        RdKafka::Topic::PARTITION_UA,
   346→        RdKafka::Producer::RK_MSG_COPY /* kafka copies payload */,
   347→        const_cast<char *>(serialized.data()),
   348→        serialized.size(),
   349→        &key,
   350→        nullptr /* headers */,
   351→        nullptr /* opaque */);
   352→
   353→    if (err != RdKafka::ERR_NO_ERROR)
   354→    {
   355→        LOG_ERROR("[EventBus] Publish failed: {}", RdKafka::err2str(err));
   356→        return false;
   357→    }
   358→
   359→    // Drive IO loop; wait up to timeout for delivery (non-blocking publish uses queue)
   360→    _producer->poll(static_cast<int>(timeout.count()));
   361→
   362→    return true;
   363→}
