   365→void EventBusFacade::Impl::subscribe(const std::string            &topic,
   366→                                     EventBusFacade::EventCallback callback)
   367→{
   368→    std::scoped_lock lock(_callbacksMtx);
   369→    if (_callbacks.find(topic) != _callbacks.end())
   370→    {
   371→        throw std::invalid_argument("Already subscribed to topic: " + topic);
   372→    }
   373→    _callbacks.emplace(topic, std::move(callback));
   374→}
   375→
   376→void EventBusFacade::Impl::consumerLoop(const std::string &topic, ConsumerPtr consumer)
   377→{
   378→    constexpr auto POLL_TIMEOUT_MS = 1000;
   379→
   380→    while (_running.load(std::memory_order_relaxed))
   381→    {
   382→        std::unique_ptr<RdKafka::Message> msg(consumer->consume(POLL_TIMEOUT_MS));
   383→        if (!msg)
   384→        {
   385→            continue;
   386→        }
   387→
   388→        if (msg->err() == RdKafka::ERR__TIMED_OUT)
   389→        {
   390→            continue; // idle poll
   391→        }
   392→        else if (msg->err() != RdKafka::ERR_NO_ERROR)
   393→        {
   394→            _consumedErr->inc();
   395→            LOG_WARN("[EventBus] Consumer error on {}: {}", topic, msg->errstr());
   396→            continue;
   397→        }
   398→
   399→        _consumedOk->inc();
   400→
   401→        // Parse payload as JSON; guard against malformed messages
   402→        nlohmann::json jsonPayload;
   403→        try
   404→        {
   405→            jsonPayload = nlohmann::json::parse(
   406→                static_cast<const char *>(msg->payload()),
   407→                static_cast<const char *>(msg->payload()) + msg->len());
   408→        }
   409→        catch (const std::exception &ex)
   410→        {
   411→            _consumedErr->inc();
   412→            LOG_ERROR("[EventBus] Malformed JSON on topic {}: {}", topic, ex.what());
   413→            continue;
   414→        }
   415→
   416→        // Dispatch to registered callback
   417→        try
   418→        {
   419→            std::scoped_lock lock(_callbacksMtx);
   420→            auto it = _callbacks.find(topic);
   421→            if (it != _callbacks.end())
   422→            {
   423→                it->second(msg->key() ? *msg->key() : "",
   424→                           jsonPayload,
   425→                           *msg);
   426→            }
   427→        }
   428→        catch (const std::exception &ex)
   429→        {
   430→            _consumedErr->inc();
   431→            LOG_ERROR("[EventBus] Callback threw: {}", ex.what());
   432→        }
   433→    }
   434→
   435→    consumer->close();
   436→    LOG_INFO("[EventBus] Consumer loop stopped for {}", topic);
   437→}
