   245→void StreamProcessor::start()
   246→{
   247→    if (running_.exchange(true))
   248→        return; // already running
   249→
   250→    RdKafka::ErrorCode rc = consumer_->subscribe({cfg_.inputTopic});
   251→    if (rc != RdKafka::ERR_NO_ERROR) {
   252→        throw std::runtime_error("Failed to subscribe to topic '" + cfg_.inputTopic +
   253→                                 "': " + RdKafka::err2str(rc));
   254→    }
   255→
   256→    worker_ = std::thread(&StreamProcessor::consumeLoop, this);
   257→}
