   282→void StreamProcessor::consumeLoop()
   283→{
   284→    while (running_) {
   285→        std::unique_ptr<RdKafka::Message> msg{consumer_->consume(500)};
   286→        if (!msg) continue;
   287→
   288→        switch (msg->err()) {
   289→        case RdKafka::ERR_NO_ERROR: {
   290→            std::string payload{static_cast<const char*>(msg->payload()),
   291→                                static_cast<std::size_t>(msg->len())};
   292→            asyncTransform(payload, msg->key() ? std::optional<std::string>(*msg->key()) : std::nullopt);
   293→            break;
   294→        }
   295→        case RdKafka::ERR__TIMED_OUT:
   296→            // simply poll again
   297→            break;
   298→        default:
   299→            std::cerr << "[StreamProcessor] Kafka error: " << msg->errstr() << "\n";
   300→            break;
   301→        }
   302→    }
   303→}
