   305→void StreamProcessor::asyncTransform(const std::string&               payload,
   306→                                     const std::optional<std::string> key)
   307→{
   308→    taskGroup_.run([this, payload, key] {
   309→        const auto start = Clock::now();
   310→        try {
   311→            Json in  = Json::parse(payload);
   312→            auto it  = in.find("signal_type");
   313→            if (it == in.end() || !it->is_string()) {
   314→                throw std::runtime_error("Missing 'signal_type' field");
   315→            }
   316→
   317→            const std::string signalType = *it;
   318→
   319→            std::unique_ptr<TransformationStrategy> *found = nullptr;
   320→            {
   321→                std::lock_guard<std::mutex> lk{stratMtx_};
   322→                for (auto& strat : strategies_) {
   323→                    if (strat->supports(signalType)) {
   324→                        found = &strat;
   325→                        break;
   326→                    }
   327→                }
   328→            }
   329→
   330→            if (!found) {
   331→                throw std::runtime_error("No strategy for signal_type=" + signalType);
   332→            }
   333→
   334→            Json out         = (*found)->transform(in);
   335→            out["timestamp"] = detail::nowUtcIso8601();
   336→
   337→            std::string outPayload = out.dump();
   338→
   339→            RdKafka::ErrorCode rc = producer_->produce(
   340→                cfg_.outputTopic,
   341→                RdKafka::Topic::PARTITION_UA,
   342→                RdKafka::Producer::RK_MSG_COPY,
   343→                const_cast<char*>(outPayload.data()),
   344→                outPayload.size(),
   345→                key ? &(*key) : nullptr,
   346→                nullptr);
   347→
   348→            if (rc != RdKafka::ERR_NO_ERROR) {
   349→                throw std::runtime_error("Kafka produce failed: " + RdKafka::err2str(rc));
   350→            }
   351→
   352→            producer_->poll(0); // serve delivery cb
   353→
   354→            const auto durMs =
   355→                std::chrono::duration_cast<std::chrono::milliseconds>(Clock::now() - start).count();
   356→            emitMetric("processing_latency_ms", static_cast<double>(durMs));
   357→        }
   358→        catch (const std::exception& ex) {
   359→            std::cerr << "[StreamProcessor] Transformation error: " << ex.what() << "\n";
   360→            deadLetterQueue_.push(payload);
   361→            emitMetric("dead_letter_total", 1.0);
   362→        }
   363→    });
   364→}
