    43→
    44→/* ---------- Utility Types ------------------------------------------------ */
    45→
    46→enum class Severity : uint8_t
    47→{
    48→    Info,
    49→    Warning,
    50→    Critical
    51→};
    52→
    53→/* Fully-qualified alert message routed to nurse stations, etc. */
    54→struct AlertMessage
    55→{
    56→    std::string patient_id;
    57→    std::string rule_id;          // Identifier of the rule that triggered
    58→    Severity    severity;
    59→    std::string description;
    60→    std::string timestamp_utc;    // ISO-8601
    61→};
