    63→/* Callback signature for clients that wish to observe alerts. */
    64→using AlertCallback = std::function<void(const AlertMessage&)>;
    65→
    66→/* ---------- Alerting Service -------------------------------------------- */
    67→
    68→class AlertingService final
    69→{
    70→public:
    71→    explicit AlertingService(const nlohmann::json& config);
    72→    ~AlertingService();
    73→
    74→    AlertingService(const AlertingService&)            = delete;
    75→    AlertingService& operator=(const AlertingService&) = delete;
    76→
    77→    void start();
