    98→    /* Evaluate one numeric value against thresholds. */
    99→    std::optional<AlertMessage>
   100→    evaluate(const std::string& patient_id,
   101→             const std::string& signal_id,
   102→             double            value,
   103→             const std::string& iso_ts) const;
