   141→/* Convert Severity enum to string for logging or serialization. */
   142→std::string to_string(Severity s)
   143→{
   144→    switch (s)
   145→    {
   146→    case Severity::Info:     return "INFO";
   147→    case Severity::Warning:  return "WARNING";
   148→    case Severity::Critical: return "CRITICAL";
   149→    }
   150→    return "UNKNOWN";
   151→}
   152→
   153→/* Make ISO-8601 timestamp for “now”. */
   154→std::string iso8601_now()
   155→{
   156→    using namespace std::chrono;
   157→    auto now   = system_clock::now();
   158→    auto itt   = system_clock::to_time_t(now);
   159→    auto tm    = *std::gmtime(&itt);
   160→    char buf[32];
   161→    strftime(buf, sizeof(buf), "%Y-%m-%dT%H:%M:%SZ", &tm);
   162→    return buf;
   163→}
   164→
   165→} // anonymous namespace
   166→
   167→/* -------------------- ctor / dtor --------------------------------------- */
   168→
   169→AlertingService::AlertingService(const nlohmann::json& config)
   170→{
   171→    /* Configure structured console logger (colorized). */
   172→    log_ = spdlog::stdout_color_mt("AlertingService");
   173→    log_->set_pattern("[%Y-%m-%d %H:%M:%S.%e] [%^%l%$] %v");
   174→
   175→    try
   176→    {
   177→        loadRules(config.at("rules"));
   178→        if (!initKafka(config.at("kafka")))
   179→        {
   180→            throw std::runtime_error("Failed to initialize Kafka subsystem");
   181→        }
   182→    }
   183→    catch (const std::exception& ex)
   184→    {
   185→        log_->critical("Configuration error: {}", ex.what());
   186→        throw; // propagate — service cannot run without valid config
   187→    }
   188→}
   189→
   190→AlertingService::~AlertingService()
   191→{
   192→    stop(); /* Ensure worker is stopped before destruction. */
   193→}
