   119→/*--------------------------------------------------------*
   120→ | Priority queue wrapper                                 |
   121→ *--------------------------------------------------------*/
   122→class TaskQueue
   123→{
   124→public:
   125→    void push(std::shared_ptr<ScheduledTask> task)
   126→    {
   127→        std::lock_guard<std::mutex> lk(_mtx);
   128→        _pq.push(std::move(task));
   129→        _cv.notify_one();
