   131→
   132→    std::shared_ptr<ScheduledTask> pop()
   133→    {
   134→        std::lock_guard<std::mutex> lk(_mtx);
   135→        if (_pq.empty())
   136→            return nullptr;
   137→        auto task = _pq.top();
   138→        _pq.pop();
   139→        return task;
   140→    }
   141→
   142→    std::shared_ptr<ScheduledTask> top()
   143→    {
   144→        std::lock_guard<std::mutex> lk(_mtx);
   145→        if (_pq.empty())
   146→            return nullptr;
   147→        return _pq.top();
   148→    }
   149→
   150→    void waitForNextDue(std::unique_lock<std::mutex>& lk, std::chrono::steady_clock::time_point tp)
   151→    {
   152→        _cv.wait_until(lk, tp, [this, tp] {
   153→            return _shutdown || _pq.empty() || _pq.top()->nextFire() < tp;
   154→        });
   155→    }
   156→
   157→    bool empty()
   158→    {
   159→        std::lock_guard<std::mutex> lk(_mtx);
   160→        return _pq.empty();
   161→    }
   162→
