   257→            metrics::incrementCounter("scheduler.task.canceled");
   258→        }
   259→    }
   260→
   261→    /*
   262→     * Start coordinator thread (idempotent).
   263→     */
   264→    void start()
   265→    {
   266→        std::lock_guard<std::mutex> lk(_stateMtx);
   267→        if (_running)
   268→            return;
   269→
   270→        _running   = true;
   271→        _coordinatorThread = std::thread([this]() { coordinatorLoop(); });
   272→
   273→        spdlog::info("SchedulingService started");
   274→    }
   275→
   276→    /*
   277→     * Graceful shutdown. Blocks until all executing tasks complete.
   278→     */
   279→    void shutdown()
   280→    {
   281→        {
   282→            std::lock_guard<std::mutex> lk(_stateMtx);
   283→            if (!_running)
   284→                return;
   285→            _running = false;
   286→        }
   287→
   288→        _queue.shutdown();
