   298→    bool isRunning() const noexcept
   299→    {
   300→        std::lock_guard<std::mutex> lk(_stateMtx);
   301→        return _running;
   302→    }
   303→
   304→private:
   305→    SchedulingService()  = default;
   306→    ~SchedulingService() { shutdown(); }
   307→
   308→    void coordinatorLoop()
   309→    {
   310→        metrics::setGauge("scheduler.state", 1);
   311→        spdlog::debug("SchedulingService coordinator loop entered");
   312→
   313→        std::unique_lock<std::mutex> lock(_sleepMtx);
   314→
   315→        while (true)
   316→        {
   317→            if (_queue.isShutdown())
   318→                break;
