   336→            }
   337→
   338→            // Pop & execute
   339→            _queue.pop();
   340→
   341→            // Dispatch asynchronously; TBB handles pooling
   342→            nextTask->dispatch(_taskGroup);
   343→
   344→            // Push back for next round
   345→            _queue.push(std::move(nextTask));
   346→        }
   347→    }
   348→
   349→    std::unordered_map<std::string, std::shared_ptr<ScheduledTask>> _tasks;
   350→    std::mutex                                                      _mapMtx;
   351→
   352→    TaskQueue       _queue;
   353→    tbb::task_group _taskGroup;
   354→    tbb::task_group _noopGroup; // used for cancel cleanup
   355→
   356→    std::thread _coordinatorThread;
   357→    std::mutex  _sleepMtx; // used with TaskQueue CV
   358→
   359→    mutable std::mutex _stateMtx;
   360→    bool               _running{false};
   361→};
