   181→        std::string var{ *env };
   182→        if (var.rfind(prefix, 0) != 0) continue; // skip non-prefixed
   183→        auto eqPos = var.find('=');
   184→        if (eqPos == std::string::npos) continue;
   185→
   186→        std::string key = var.substr(prefix.size(), eqPos - prefix.size());
   187→        std::string val = var.substr(eqPos + 1);
   188→
   189→        // Normalize: UPPERCASE_WITH_UNDERSCORES -> lowercase.with.dots
   190→        utils::strings::toLower(key);
   191→        std::replace(key.begin(), key.end(), '_', '.');
   192→
   193→        // Drill/create hierarchy
   194→        json* cursor = &cfg;
   195→        auto  tokens = utils::strings::split(key, '.');
   196→        for (size_t i = 0; i < tokens.size(); ++i) {
   197→            const auto& tk = tokens[i];
   198→            if (i + 1 == tokens.size()) {
   199→                // leaf
   200→                (*cursor)[tk] = val;
   201→            } else {
   202→                cursor = &((*cursor)[tk]);
   203→            }
   204→        }
   205→        _logger->debug("Environment override: {} -> {}", key, val);
   206→    }
   207→#endif
   208→}
