   234→void ConfigManager::notifyCallbacks()
   235→{
   236→    std::vector<CallbackFn> snapshot;
   237→    {
   238→        std::unique_lock lock{ _callbackMutex };
   239→        snapshot = _callbacks; // copy
   240→    }
   241→
   242→    for (auto& cb : snapshot) {
