    59→/**************************************************************************************************
    60→ * ECGTransformationStrategy – performs baseline wander removal,  resampling (250 Hz), 12-lead
    61→ *                              normalization and quality checks (QRS detection, beats count).
    62→ **************************************************************************************************/
    63→class ECGTransformationStrategy final : public TransformationStrategy
    64→{
    65→public:
    66→    explicit ECGTransformationStrategy(json config) :
    67→        _hpCutoffHz  (config.value("high_pass_cutoff_hz", 0.5)),
    68→        _resampleHz  (config.value("target_sample_rate_hz", 250)),
    69→        _leadCount   (config.value("lead_count", 12u))
    70→    {
    71→        spdlog::debug("[ECG] Instantiated ECGTransformationStrategy – config ♥ {}", config.dump());
    72→    }
    73→
    74→    std::string id() const noexcept override { return "ecg"; }
    75→
    76→    CuratedSignalFrame transform(const RawSignalFrame& raw,
    77→                                 const TransformationContext& ctx) const override
    78→    {
    79→        if (raw.sample_rate_hz == 0.0) {
    80→            CI360_THROW(ci360::common::InvalidArgument,
    81→                        "Raw sample_rate_hz must be > 0 for ECG transformation");
    82→        }
    83→
    84→        //---------------------------------- 1. Baseline-Wander Removal ----------------------------
    85→        auto filtered = ci360::signal_processing::filters::butterworth_high_pass(
    86→            raw.samples, raw.sample_rate_hz, _hpCutoffHz, /*order*/2);
    87→
    88→        //---------------------------------- 2. Resampling (if required) ----------------------------
    89→        if (raw.sample_rate_hz != _resampleHz) {
    90→            filtered = ci360::signal_processing::dsp::resample(filtered,
    91→                                                               raw.sample_rate_hz,
    92→                                                               _resampleHz);
    93→        }
    94→
    95→        //---------------------------------- 3. Quality Checks & Beat Validation -------------------
    96→        auto validation = ci360::signal_processing::quality::run_arrhythmia_validation(filtered,
    97→                                                                                       _resampleHz,
    98→                                                                                       ctx.patient_meta);
    99→
   100→        //---------------------------------- 4. Assemble Curated SignalFrame -----------------------
   101→        CuratedSignalFrame curated;
   102→        curated.uuid               = Uuid::random();
   103→        curated.modality           = "ECG";
   104→        curated.sample_rate_hz     = _resampleHz;
   105→        curated.samples            = std::move(filtered);
   106→        curated.quality_report     = std::move(validation.report);
   107→        curated.ingestion_timestamp= raw.ingestion_timestamp;
   108→        curated.processing_host    = ctx.host_name;
   109→        curated.processing_epoch_ms= ci360::common::now_epoch_ms();
   110→
   111→        return curated;
   112→    }
   113→
   114→private:
   115→    double   _hpCutoffHz;
   116→    double   _resampleHz;
