   265→ *
   266→ *  @param modality     Case-insensitive modality identifier (e.g. “ECG”, “bp”, “SpO₂”)
   267→ *  @param cfg          Site / pipeline specific configuration parameters.
   268→ *
   269→ *  @throws UnsupportedModalityError if no strategy has been registered for the given modality.
   270→ **************************************************************************************************/
   271→std::unique_ptr<TransformationStrategy>
   272→TransformationStrategy::make(std::string modality, const json& cfg)
   273→{
   274→    // Normalize modality to lower case
   275→    std::transform(modality.begin(), modality.end(),
   276→                   modality.begin(), [](unsigned char c){ return std::tolower(c); });
   277→
   278→    /* Lazy initialization of built-in strategies */
   279→    std::call_once(_registration_once_flag, register_builtin_strategies);
   280→
   281→    std::shared_lock guard(_registry_mutex);
   282→    const auto& registry = registry_instance();
   283→    auto it = registry.find(modality);
   284→
   285→    if (it == registry.end()) {
   286→        std::stringstream ss;
   287→        ss << "Unsupported or unregistered modality: [" << modality << "]";
   288→        spdlog::error(ss.str());
   289→        CI360_THROW(ci360::common::UnsupportedModalityError, ss.str());
   290→    }
   291→
   292→    try {
   293→        return (it->second)(cfg);      // Invoke factory functor
   294→    }
   295→    catch (const std::exception& ex) {
   296→        spdlog::error("Failed to instantiate TransformationStrategy for modality '{}' – {}",
   297→                      modality, ex.what());
   298→        throw;  // propagate
   299→    }
   300→}
