   303→ * TransformationStrategy::register_custom
   304→ *
   305→ *      API for plugin authors to register their own strategy implementation at run-time.
   306→ *
   307→ *  @param modality      Unique, lower-case modality identifier.
   308→ *  @param factory       Functor that returns a std::unique_ptr<TransformationStrategy>.
   309→ *
   310→ *  @returns true if registration succeeded, false if the modality ID is already in use.
   311→ **************************************************************************************************/
   312→bool TransformationStrategy::register_custom(std::string modality,
   313→                                             StrategyFactory factory)
   314→{
   315→    std::transform(modality.begin(), modality.end(),
   316→                   modality.begin(), [](unsigned char c){ return std::tolower(c); });
   317→
   318→    std::unique_lock guard(_registry_mutex);
   319→    auto& registry = registry_instance();
   320→
   321→    auto [it, inserted] = registry.emplace(std::move(modality), std::move(factory));
   322→    if (!inserted) {
   323→        spdlog::warn("Cannot register custom TransformationStrategy – modality '{}' already exists",
   324→                     it->first);
   325→    } else {
   326→        spdlog::info("Custom TransformationStrategy for modality '{}' registered", it->first);
   327→    }
   328→    return inserted;
   329→}
