    95→/**
    96→ * Encrypts `src` into `dst` using AES-256-GCM.
    97→ * Layout of dst = [ IV | TAG | CIPHERTEXT ].
    98→ */
    99→void aes256_gcm_encrypt(const std::vector<std::uint8_t>& src,
   100→                        const std::array<std::uint8_t, 32>& key,
   101→                        std::vector<std::uint8_t>&        dst)
   102→{
   103→    std::array<std::uint8_t, kAesIvBytes> iv{};
   104→    if (RAND_bytes(iv.data(), iv.size()) != 1) { throw std::runtime_error("RAND_bytes failed"); }
   105→
   106→    const EVP_CIPHER* alg = EVP_aes_256_gcm();
   107→
   108→    EvpCipherCtx ctx;
   109→    if (EVP_EncryptInit_ex(ctx.get(), alg, nullptr, nullptr, nullptr) != 1)
   110→        throw std::runtime_error("EVP_EncryptInit_ex failed (alg)");
   111→
   112→    if (EVP_CIPHER_CTX_ctrl(ctx.get(), EVP_CTRL_GCM_SET_IVLEN, iv.size(), nullptr) != 1)
   113→        throw std::runtime_error("EVP_CIPHER_CTX_ctrl failed (iv len)");
   114→
   115→    if (EVP_EncryptInit_ex(ctx.get(), nullptr, nullptr, key.data(), iv.data()) != 1)
   116→        throw std::runtime_error("EVP_EncryptInit_ex failed (key/iv)");
   117→
   118→    std::vector<std::uint8_t> cipher(src.size() + EVP_CIPHER_block_size(alg));
   119→    int                      out_len = 0;
   120→
   121→    if (EVP_EncryptUpdate(ctx.get(), cipher.data(), &out_len, src.data(),
   122→                          static_cast<int>(src.size())) != 1)
   123→        throw std::runtime_error("EVP_EncryptUpdate failed");
   124→
   125→    int tmp_len = 0;
   126→    if (EVP_EncryptFinal_ex(ctx.get(), cipher.data() + out_len, &tmp_len) != 1)
   127→        throw std::runtime_error("EVP_EncryptFinal_ex failed");
   128→
   129→    out_len += tmp_len;
   130→    cipher.resize(out_len);
   131→
   132→    std::array<std::uint8_t, kAesTagBytes> tag{};
   133→    if (EVP_CIPHER_CTX_ctrl(ctx.get(), EVP_CTRL_GCM_GET_TAG, tag.size(), tag.data()) != 1)
   134→        throw std::runtime_error("EVP_CIPHER_CTX_ctrl failed (get tag)");
   135→
   136→    // IV + TAG + CIPHER
   137→    dst.resize(iv.size() + tag.size() + cipher.size());
   138→    std::uint8_t* p = dst.data();
   139→    std::memcpy(p, iv.data(), iv.size());
   140→    p += iv.size();
   141→    std::memcpy(p, tag.data(), tag.size());
   142→    p += tag.size();
   143→    std::memcpy(p, cipher.data(), cipher.size());
   144→}
