   192→inline std::string to_iso_path(const std::chrono::system_clock::time_point& tp)
   193→{
   194→    std::time_t          tt = std::chrono::system_clock::to_time_t(tp);
   195→    std::tm              tm{};
   196→#if defined(_WIN32)
   197→    gmtime_s(&tm, &tt);
   198→#else
   199→    gmtime_r(&tt, &tm);
   200→#endif
   201→    std::ostringstream oss;
   202→    oss << std::put_time(&tm, "%Y/%m/%d/%H%M%S");
   203→    return oss.str();
   204→}
