   119→/**
   120→ * Return mean and standard deviation of the sample vector, ignoring NaNs.
   121→ */
   122→inline std::pair<double, double>
   123→mean_stddev(const std::vector<double>& data)
   124→{
   125→    std::vector<double> filtered;
   126→    filtered.reserve(data.size());
   127→    for (double v : data)
   128→    {
   129→        if (!std::isnan(v))
   130→            filtered.push_back(v);
   131→    }
   132→    if (filtered.empty())
   133→        return {std::numeric_limits<double>::quiet_NaN(),
   134→                std::numeric_limits<double>::quiet_NaN()};
   135→
   136→    double mean = std::accumulate(filtered.begin(), filtered.end(), 0.0)
   137→                / filtered.size();
   138→
   139→    double accum = 0.0;
   140→    for (double v : filtered)
   141→        accum += (v - mean) * (v - mean);
   142→
   143→    double stddev = std::sqrt(accum / filtered.size());
   144→    return {mean, stddev};
   145→}
   146→
   147→/**
   148→ * Return fraction (0.0 – 1.0) of NaN values inside the vector.
   149→ */
   150→inline double fraction_nan(const std::vector<double>& data)
   151→{
   152→    if (data.empty()) return 1.0;
   153→    std::size_t invalid = std::count_if(
   154→        data.begin(), data.end(), [](double v) { return std::isnan(v); });
   155→    return static_cast<double>(invalid) / data.size();
   156→}
