   161→/* ========================================================================
   162→ *                  ECG  – Arrhythmia & Signal-Quality checks
   163→ * ===================================================================== */
   164→
   165→class ECGQualityCheckStrategy final : public IQualityCheckStrategy
   166→{
   167→public:
   168→    explicit ECGQualityCheckStrategy(const json& cfg)
   169→    {
   170→        // Load thresholds from configuration or fallback to defaults.
   171→        amp_min_mv_          = cfg.value("amp_min_mv",   -5.0);
   172→        amp_max_mv_          = cfg.value("amp_max_mv",    5.0);
   173→        wander_max_std_mv_   = cfg.value("wander_std_mv", 0.5);
   174→        nan_threshold_       = cfg.value("nan_threshold", 0.05);
   175→        hr_range_min_bpm_    = cfg.value("hr_min_bpm",    30.0);
   176→        hr_range_max_bpm_    = cfg.value("hr_max_bpm",   220.0);
   177→        sampling_rate_expect_ = cfg.value("expected_sampling_hz", 250.0);
   178→    }
   179→
   180→    QualityReport validate(const SignalPacket& packet) noexcept override
   181→    {
   182→        QualityReport rep;
   183→        try
   184→        {
   185→            if (packet.type != SignalType::ECG)
   186→                throw std::invalid_argument("SignalType mismatch");
   187→
   188→            // 1) Check sampling rate
   189→            if (std::fabs(packet.sampling_rate_hz - sampling_rate_expect_) > 1.0)
   190→            {
   191→                rep.add_warning("Sampling rate deviates from expectation ("
   192→                                + std::to_string(packet.sampling_rate_hz) + "Hz)");
   193→            }
   194→
   195→            // 2) Check NaN ratio
   196→            double nan_frac = detail::fraction_nan(packet.values);
   197→            if (nan_frac > nan_threshold_)
   198→            {
   199→                rep.add_error("Excessive invalid samples ("
   200→                              + std::to_string(nan_frac * 100) + "% NaN)");
   201→            }
   202→
   203→            // 3) Amplitude envelope
   204→            auto [mean, stddev] = detail::mean_stddev(packet.values);
   205→            double min_v = *std::min_element(packet.values.begin(),
   206→                                             packet.values.end());
   207→            double max_v = *std::max_element(packet.values.begin(),
   208→                                             packet.values.end());
   209→
   210→            if (min_v < amp_min_mv_ || max_v > amp_max_mv_)
   211→            {
   212→                rep.add_error("Amplitude out of bounds: [" +
   213→                              std::to_string(min_v) + " , "
   214→                              + std::to_string(max_v) + "] mV");
   215→            }
   216→
   217→            // 4) Baseline wander (use low-frequency estimate ≈ mean)
   218→            if (stddev > wander_max_std_mv_)
   219→            {
   220→                rep.add_warning("High baseline wander (σ="
   221→                                + std::to_string(stddev) + "mV)");
   222→            }
   223→
   224→            // 5) Very primitive heart-rate windowing based on zero-crossings
   225→            std::size_t zero_crossings = 0;
   226→            for (std::size_t i = 1; i < packet.values.size(); ++i)
   227→            {
   228→                if ((packet.values[i - 1] < 0 && packet.values[i] >= 0) ||
   229→                    (packet.values[i - 1] > 0 && packet.values[i] <= 0))
   230→                    ++zero_crossings;
   231→            }
   232→            double duration_sec =
   233→                static_cast<double>(packet.values.size()) / packet.sampling_rate_hz;
   234→            double rr_intervals   = zero_crossings / 2.0; // two crossings per beat
   235→            double hr_bpm         = (duration_sec > 0) ? (rr_intervals / duration_sec) * 60
   236→                                                       : 0.0;
   237→
   238→            if (hr_bpm < hr_range_min_bpm_ || hr_bpm > hr_range_max_bpm_)
   239→            {
   240→                rep.add_warning("Suspicious heart-rate estimate (" +
   241→                                std::to_string(hr_bpm) + " bpm)");
   242→            }
   243→
   244→            // Decide
   245→            rep.passed = rep.errors.empty();
   246→        }
   247→        catch (const std::exception& ex)
   248→        {
   249→            rep.add_error(std::string("ECG validation internal failure: ") + ex.what());
   250→            rep.passed = false;
   251→        }
   252→        return rep;
   253→    }
   254→
   255→private:
   256→    double amp_min_mv_;
   257→    double amp_max_mv_;
   258→    double wander_max_std_mv_;
   259→    double nan_threshold_;
   260→    double hr_range_min_bpm_;
   261→    double hr_range_max_bpm_;
   262→    double sampling_rate_expect_;
   263→};
