class ThreadPoolManager {
public:
    ThreadPoolManager(const core::ConfigManager& cfg) {
        auto realtimeCfg = cfg.getThreadPoolConfig("realtime");
        auto batchCfg = cfg.getThreadPoolConfig("batch");

        std::size_t totalCores = std::thread::hardware_concurrency();

        // Realtime pool: fixed allocation
        std::size_t realtimeCores = realtimeCfg
            ? realtimeCfg->max_concurrency
            : std::min<std::size_t>(4, totalCores / 2);

        // Batch pool: remaining cores
        std::size_t batchCores = batchCfg && batchCfg->max_concurrency > 0
            ? batchCfg->max_concurrency
            : totalCores - realtimeCores;

        // Create isolated TBB task arenas
        _realtimeArena = std::make_unique<tbb::task_arena>(
            static_cast<int>(realtimeCores),
            1  // Reserved for high-priority master thread
        );

        _batchArena = std::make_unique<tbb::task_arena>(
            static_cast<int>(batchCores),
            0  // No reserved threads
        );

        spdlog::info("ThreadPoolManager: realtime={} cores, batch={} cores",
                     realtimeCores, batchCores);
    }

    tbb::task_arena& realtimeArena() { return *_realtimeArena; }
    tbb::task_arena& batchArena() { return *_batchArena; }

private:
    std::unique_ptr<tbb::task_arena> _realtimeArena;
    std::unique_ptr<tbb::task_arena> _batchArena;
};

